import './App.css'
import { BrowserRouter, Routes, Route } from 'react-router-dom'

// Importation de la page Main

import Main from './Main/Main'


function App(){
  return(
    <BrowserRouter>
        <Routes>
            <Route path='/' element={<Main />} />
        </Routes>
    </BrowserRouter>
  )
}


export default App;
